package main.rice.obj;

public abstract class AIterablePyObj<InnerType extends APyObj<?>, OuterType> extends APyObj<OuterType> {
}

package main.rice.obj;

import java.util.Objects;

public abstract class APyObj<T> {

    protected T value;

    public T getValue() {
        return this.value;
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null || getClass() != obj.getClass()) return false;
        APyObj<?> other = (APyObj<?>) obj;
        return Objects.equals(this.value, other.value);
    }

    @Override
    public int hashCode() {
        return Objects.hashCode(this.value);
    }
}

package main.rice.obj;

public class PyBoolObj extends APyObj<Boolean> {

    public PyBoolObj(Boolean value) {
        this.value = value;
    }

    @Override
    public String toString() {
        return this.value ? "True" : "False";
    }
}

package main.rice.obj;

public class PyCharObj extends APyObj<Character> {

    public PyCharObj(Character value) {
        this.value = value;
    }

    @Override
    public String toString() {
        return this.value.toString();
    }
}

package main.rice.obj;

import java.util.Map;
import java.util.stream.Collectors;

public class PyDictObj<K extends APyObj<?>, V extends APyObj<?>> extends APyObj<Map<K, V>> {

    public PyDictObj(Map<K, V> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        return "{" + this.value.entrySet().stream()
            .map(e -> e.getKey().toString() + ": " + e.getValue().toString())
            .collect(Collectors.joining(", ")) + "}";
    }
}

package main.rice.obj;

public class PyFloatObj extends APyObj<Double> {

    public PyFloatObj(Double value) {
        this.value = value;
    }

    @Override
    public String toString() {
        return this.value.toString();
    }
}

package main.rice.obj;

public class PyIntObj extends APyObj<Integer> {

    public PyIntObj(Integer value) {
        this.value = value;
    }

    @Override
    public String toString() {
        return this.value.toString();
    }
}

package main.rice.obj;

import java.util.List;
import java.util.stream.Collectors;

public class PyListObj<T extends APyObj<?>> extends AIterablePyObj<T, List<T>> {

    public PyListObj(List<T> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        return "[" + this.value.stream()
            .map(Object::toString)
            .collect(Collectors.joining(", ")) + "]";
    }
}

package main.rice.obj;

import java.util.Set;
import java.util.stream.Collectors;

public class PySetObj<T extends APyObj<?>> extends AIterablePyObj<T, Set<T>> {

    public PySetObj(Set<T> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        if (this.value.isEmpty()) {
            return "set()";
        }
        return "{" + this.value.stream()
            .map(Object::toString)
            .collect(Collectors.joining(", ")) + "}";
    }
}

package main.rice.obj;

import java.util.ArrayList;
import java.util.List;

public class PyStringObj extends AIterablePyObj<PyCharObj, List<PyCharObj>> {

    private final String str;

    public PyStringObj(String str) {
        this.str = str;
        this.value = new ArrayList<>();
        for (char c : str.toCharArray()) {
            this.value.add(new PyCharObj(c));
        }
    }

    @Override
    public String toString() {
        return "'" + this.str + "'";
    }
}

package main.rice.obj;

import java.util.List;
import java.util.stream.Collectors;

public class PyTupleObj<T extends APyObj<?>> extends AIterablePyObj<T, List<T>> {

    public PyTupleObj(List<T> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        if (this.value.size() == 1) {
            return "(" + this.value.get(0).toString() + ",)";
        }
        return "(" + this.value.stream()
            .map(Object::toString)
            .collect(Collectors.joining(", ")) + ")";
    }
}

